const body = $input.first().json.body;

// Slug: usa fornecido ou gera a partir do título
const slug = body.slug || body.titulo
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

// ID determinístico baseado no slug
const id = `imovel-${slug}`;

// Monta o documento
const doc = {
  _id: id,
  _type: 'imovel',
  titulo: body.titulo,
  slug: { _type: 'slug', current: slug },
  status: body.status || 'Disponível',
  finalidade: body.finalidade || 'Venda',
  tipo: body.tipo || 'Apartamento',
  destaque: body.destaque === true || body.destaque === 'true',
  preco: body.preco ? Number(body.preco) : null,
  precoCondominio: body.precoCondominio ? Number(body.precoCondominio) : null,
  quartos: body.quartos ? Number(body.quartos) : null,
  suites: body.suites ? Number(body.suites) : null,
  banheiros: body.banheiros ? Number(body.banheiros) : null,
  vagas: body.vagas ? Number(body.vagas) : null,
  areaUtil: body.areaUtil ? Number(body.areaUtil) : null,
  areaTotal: body.areaTotal ? Number(body.areaTotal) : null,
  andar: body.andar ? Number(body.andar) : null,
  descricao: body.descricao || '',
  endereco: body.endereco || ''
};

// Referência ao bairro (obrigatório)
if (body.bairroId) {
  doc.bairro = { _type: 'reference', _ref: body.bairroId };
}

// Referência ao condomínio (opcional)
if (body.condominioId) {
  doc.condominio = { _type: 'reference', _ref: body.condominioId };
}

// metaTitle e metaDescription (opcional)
if (body.metaTitle) doc.metaTitle = body.metaTitle;
if (body.metaDescription) doc.metaDescription = body.metaDescription;

return [{ json: { mutations: [{ createOrReplace: doc }] } }];
